// Dynamically create dresses
(() => {
	let flagged = [];

	for (let key of Object.keys(KDModelDresses)) {
		if (!KinkyDungeonOutfitsBase.some((outfit) => {return outfit.name == key || outfit.dress == key})) {
			flagged.push({name: key, dress: key, shop: false, rarity: 1},);
		}
	}
	for (let f of flagged) {
		KinkyDungeonOutfitsBase.push(f);
	}
})();
